require('framework.async.OKAsyncLoader')ConcurrentQueue=AsyncLoader:extend()function ConcurrentQueue:new()ConcurrentQueue.super.new(self)self.shouldCancelOnAnyError=true;self.loaders={}end;function ConcurrentQueue:setShouldCancelOnAnyError(a)self.shouldCancelOnAnyError=a end;function ConcurrentQueue:addLoader(b)assert(not self:isLoading(),"启动之后就不能添加loader了")table.insert(self.loaders,b)end;function ConcurrentQueue:_startLoad()if#self.loaders==0 then System:setTimeOut(function()self:notifyResult(nil,nil)end,0)return end;for c,d in ipairs(self.loaders)do if self:isForceAbort()then return end;d:setQueueCallback(function(b)self:onLoaderFinished(b)end)d:start()end end;function ConcurrentQueue:_cancel()for c,d in ipairs(self.loaders)do d:cancel()end end;function ConcurrentQueue:count()return#self.loaders end;function ConcurrentQueue:hasAllFinished()for c,d in ipairs(self.loaders)do if not d.finished then return false end end;return true end;function ConcurrentQueue:anyError()for c,d in ipairs(self.loaders)do if d.error then return d.error end end;return nil end;function ConcurrentQueue:onLoaderFinished(b)if b.error then if self.shouldCancelOnAnyError then self:cancel()self:notifyResult(nil,b.error,true)return end end;if self:hasAllFinished()then self:notifyResult(nil,nil)end end;return ConcurrentQueue
